    .toLowerCase();

  // Only process Pending invoices
  if (status !== 'pending') continue;

  // Handle Due Date (skip if not present or invalid)
  let isOverdue = false;
  let dueDateFormatted = '';
  let daysOverdue = 0;

  if (row['Due Date']) {
    const due = new Date(row['Due Date']);

    if (!isNaN(due)) {
      due.setHours(0, 0, 0, 0);

      if (due < today) {
        isOverdue = true;
        daysOverdue = Math.floor((today - due) / (1000 * 60 * 60 * 24));

        dueDateFormatted = due.toLocaleDateString('en-IN', {
          day: 'numeric',
          month: 'short',
          year: 'numeric'
        });
      }
    }
  }

  // Only push if actually overdue
  if (!isOverdue) continue;

  overdue.push({
    json: {
      InvoiceNumber: row['Invoice Number'] || '',
      CompanyName: row['Company Name'] || '',
      ClientName: row['Contact Person'] || '',
      ClientEmail: row['Client Email'] || '',
      TotalAmount: row['Total Amount'] || '',
      DueDate: dueDateFormatted,
      DaysOverdue: daysOverdue
    }
  });
}

// ✅ Final Output (clean + usable downstream)
return [{
  json: {
    hasOverdue: overdue.length > 0,
    count: overdue.length,
    invoices: overdue.map(item => item.json)
  }
}];

