function parseItems(rawText) {
  const lines = rawText.split(/\n/).map(l => l.trim()).filter(Boolean);
  const items = [];

  function parseSingleLine(line) {
  if (!line) return null;

  const parts = line.split(';').map(p => p.trim());

  // New format: Product ; Quantity ; Price
  if (parts.length === 3) {
    return {
      desc: parts[0],
      qty: parseInt(parts[1]) || 1,
      price: parseFloat(parts[2].replace(/[^\d.]/g,'')) || 0
    };
